 15→/**
 16→ * Evaluation API route.
 17→ * POST /api/training/{tenant}/evaluate
 18→ * Computes the final pass/fail decision for a training session in `evaluating` state.
 19→ */
 20→
 21→import { getSnapshot } from "@/config/index";
 22→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 23→import { logEvaluationCompleted, logSessionExhausted } from "@/training/audit";
 24→import { computeAggregateScore, identifyWeakAreas, isPassing } from "@/training/score-calculator";
 25→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 26→import { StateTransitionError, transitionSession } from "@/training/state-machine";
 27→import { NextResponse } from "next/server";
 28→
 29→const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 30→const sessionRepo = new SessionRepository(storage);
 31→
 32→export async function POST(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 33→  const { tenant: tenantSlug } = await params;
 34→  const tenantId = request.headers.get("x-tenant-id");
 35→  const employeeId = request.headers.get("x-employee-id");
 36→
 37→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 38→    return NextResponse.json(
 39→      { error: "unauthorized", message: "Not authenticated" },
 40→      { status: 401 },
 41→    );
 42→  }
 43→
 44→  await storage.initialize();
 45→
 46→  // Find active session
 47→  const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 48→  if (!session) {
 49→    return NextResponse.json(
 50→      { error: "not_found", message: "No active training session found" },
 51→      { status: 404 },
 52→    );
 53→  }
 54→
 55→  // Guard: session must be in evaluating state
 56→  if (session.status !== "evaluating") {
 57→    return NextResponse.json(
 58→      {
 59→        error: "conflict",
 60→        message: `Session is in '${session.status}' state, expected 'evaluating'`,
 61→      },
 62→      { status: 409 },
 63→    );
 64→  }
 65→
 66→  // Find all modules
 67→  const modules = await sessionRepo.findModulesBySession(tenantId, session.id);
 68→
 69→  // Extract module scores (all must be non-null at this point)
 70→  const moduleScores = modules.map((m) => m.moduleScore as number);
 71→
 72→  // Compute aggregate score
 73→  const aggregateScore = computeAggregateScore(moduleScores) ?? 0;
 74→
 75→  // Get tenant training config
 76→  const snapshot = getSnapshot();
 77→  const tenant = snapshot?.tenants.get(tenantId);
 78→  const trainingConfig = tenant?.settings?.training;
 79→  const passThreshold = trainingConfig?.passThreshold ?? 0.7;
 80→  const maxAttempts = trainingConfig?.maxAttempts ?? 3;
 81→
 82→  const now = new Date().toISOString();
 83→  let nextAction: "complete" | "remediation-available" | "exhausted";
 84→  let passed: boolean;
 85→  let newStatus: "passed" | "failed" | "exhausted";
 86→  let completedAt: string | null = null;
 87→  let weakAreas: string[] | undefined;
 88→
 89→  if (isPassing(aggregateScore, passThreshold)) {
 90→    // Pass
 91→    passed = true;
 92→    newStatus = "passed";
 93→    nextAction = "complete";
 94→    completedAt = now;
 95→  } else if (session.attemptNumber < maxAttempts) {
 96→    // Failed with attempts remaining
 97→    passed = false;
 98→    newStatus = "failed";
 99→    nextAction = "remediation-available";
100→    weakAreas = identifyWeakAreas(
101→      modules.map((m) => ({ topicArea: m.topicArea, moduleScore: m.moduleScore as number })),
102→      passThreshold,
103→    );
104→  } else {
105→    // Failed and exhausted all attempts
106→    passed = false;
107→    newStatus = "exhausted";
108→    nextAction = "exhausted";
109→    completedAt = now;
110→  }
111→
112→  // Transition session state
113→  try {
114→    transitionSession(
115→      session.status,
116→      `evaluation-${newStatus}` as Parameters<typeof transitionSession>[1],
117→    );
118→  } catch (err) {
119→    if (err instanceof StateTransitionError) {
120→      return NextResponse.json({ error: "conflict", message: err.message }, { status: 409 });
121→    }
122→    throw err;
123→  }
124→
125→  // Update session
126→  const updateData: Parameters<typeof sessionRepo.updateSession>[2] = {
127→    status: newStatus,
128→    aggregateScore,
129→    ...(weakAreas !== undefined ? { weakAreas } : {}),
130→    ...(completedAt !== null ? { completedAt } : {}),
131→  };
132→
133→  try {
134→    await sessionRepo.updateSession(tenantId, session.id, updateData, session.version);
135→  } catch (err) {
136→    if (err instanceof VersionConflictError) {
137→      return NextResponse.json(
138→        { error: "conflict", message: "Session was modified by another request" },
139→        { status: 409 },
140→      );
141→    }
142→    throw err;
143→  }
144→
145→  // Audit logging
146→  await logEvaluationCompleted(
147→    storage,
148→    tenantId,
149→    employeeId,
150→    session.id,
151→    session.attemptNumber,
152→    aggregateScore,
153→    passed,
154→  );
155→
156→  if (newStatus === "exhausted") {
157→    await logSessionExhausted(
158→      storage,
159→      tenantId,
160→      employeeId,
161→      session.id,
162→      aggregateScore,
163→      session.attemptNumber,
164→    );
165→  }
166→
167→  return NextResponse.json(
168→    {
169→      sessionId: session.id,
170→      aggregateScore,
171→      passed,
172→      attemptNumber: session.attemptNumber,
173→      ...(weakAreas !== undefined ? { weakAreas } : {}),
174→      nextAction,
175→    },
176→    { status: 200 },
177→  );
178→}
