 15→/**
 16→ * Training session API routes.
 17→ * POST /api/training/{tenant}/session — start a new training session (T013)
 18→ *                                      or start remediation for a failed session (T022)
 19→ * GET  /api/training/{tenant}/session — get current session state (T014)
 20→ */
 21→
 22→import { getSnapshot } from "@/config/index";
 23→import { resolveModel } from "@/intake/ai-model-resolver";
 24→import { ProfileRepository } from "@/intake/profile-repository";
 25→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 26→import { logRemediationInitiated, logSessionStarted } from "@/training/audit";
 27→import { CurriculumGenerationError, generateCurriculum } from "@/training/curriculum-generator";
 28→import {
 29→  RemediationPlanError,
 30→  generateRemediationCurriculum,
 31→} from "@/training/remediation-planner";
 32→import { SessionRepository } from "@/training/session-repository";
 33→import { transitionSession } from "@/training/state-machine";
 34→import type { TrainingModule } from "@/training/types";
 35→import { NextResponse } from "next/server";
 36→
 37→// ---------------------------------------------------------------------------
 38→// Shared storage / repos (module-level singletons, as per existing patterns)
 39→// ---------------------------------------------------------------------------
 40→
 41→const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 42→const profileRepo = new ProfileRepository(storage);
 43→const sessionRepo = new SessionRepository(storage);
 44→
 45→// ---------------------------------------------------------------------------
 46→// Helper — strip server-only fields from module content before sending
 47→// ---------------------------------------------------------------------------
 48→
 49→function stripServerFields(module: TrainingModule): unknown {
 50→  if (!module.content) return module;
 51→  return {
 52→    ...module,
 53→    content: {
 54→      ...module.content,
 55→      scenarios: module.content.scenarios.map(({ rubric: _rubric, ...s }) => ({
 56→        ...s,
 57→        options: s.options?.map(({ correct: _correct, ...o }) => o),
 58→      })),
 59→      quiz: module.content.quiz
 60→        ? {
 61→            questions: module.content.quiz.questions.map(({ rubric: _rubric, ...q }) => ({
 62→              ...q,
 63→              options: q.options?.map(({ correct: _correct, ...o }) => o),
 64→            })),
 65→          }
 66→        : module.content.quiz,
 67→    },
 68→  };
 69→}
 70→
 71→// ---------------------------------------------------------------------------
 72→// POST — T013: Start a new training session; T022: Remediation
 73→// ---------------------------------------------------------------------------
 74→
 75→export async function POST(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 76→  const { tenant: tenantSlug } = await params;
 77→  const tenantId = request.headers.get("x-tenant-id");
 78→  const employeeId = request.headers.get("x-employee-id");
 79→
 80→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 81→    return NextResponse.json(
 82→      { error: "unauthorized", message: "Not authenticated" },
 83→      { status: 401 },
 84→    );
 85→  }
 86→
 87→  await storage.initialize();
 88→
 89→  // 1. Check for existing active session — 409 if one exists
 90→  const existingSession = await sessionRepo.findActiveSession(tenantId, employeeId);
 91→  if (existingSession) {
 92→    return NextResponse.json(
 93→      { error: "conflict", message: "An active training session already exists" },
 94→      { status: 409 },
 95→    );
 96→  }
 97→
 98→  // Resolve tenant config (needed for both fresh and remediation paths)
 99→  const snapshot = getSnapshot();
100→  const tenant = snapshot?.tenants.get(tenantSlug);
101→  if (!tenant) {
102→    return NextResponse.json({ error: "not_found", message: "Tenant not found" }, { status: 404 });
103→  }
104→  const model = resolveModel(tenant);
105→  const maxModules = tenant.settings.training?.maxModules ?? 8;
106→  const maxAttempts = tenant.settings.training?.maxAttempts ?? 3;
107→  const enableRemediation = tenant.settings.training?.enableRemediation ?? true;
108→
109→  // 2. T022: Check for a failed session with attempts remaining — start remediation
110→  const history = await sessionRepo.findSessionHistory(tenantId, employeeId, { limit: 10 });
111→  const failedSession =
112→    history.find((s) => s.status === "failed" && s.attemptNumber < maxAttempts) ?? null;
113→
114→  if (failedSession) {
115→    // 2a. Remediation must be enabled
116→    if (!enableRemediation) {
117→      return NextResponse.json(
118→        { error: "conflict", message: "Remediation is not enabled for this tenant" },
119→        { status: 409 },
120→      );
121→    }
122→
123→    // 2b. Find confirmed role profile — 404 if none
124→    const profile = await profileRepo.findByEmployee(tenantId, employeeId);
125→    if (!profile) {
126→      return NextResponse.json(
127→        { error: "not_found", message: "No confirmed role profile found" },
128→        { status: 404 },
129→      );
130→    }
131→
132→    // 2c. Generate remediation curriculum focused on weak areas
133→    const weakAreas = failedSession.weakAreas ?? [];
134→    let remediationCurriculum: Awaited<ReturnType<typeof generateRemediationCurriculum>>;
135→    try {
136→      remediationCurriculum = await generateRemediationCurriculum(
137→        weakAreas,
138→        profile,
139→        { maxModules },
140→        model,
141→      );
142→    } catch (error) {
143→      if (error instanceof RemediationPlanError) {
144→        if (error.code === "ai_unavailable") {
145→          return NextResponse.json(
146→            { error: "ai_unavailable", message: "AI service temporarily unavailable" },
147→            { status: 503 },
148→          );
149→        }
150→        return NextResponse.json(
151→          { error: "planning_failed", message: error.message },
152→          { status: 422 },
153→        );
154→      }
155→      return NextResponse.json(
156→        { error: "internal_error", message: "An unexpected error occurred" },
157→        { status: 500 },
158→      );
159→    }
160→
161→    // 2d. Increment attemptNumber and transition the failed session through remediation states
162→    const newAttemptNumber = failedSession.attemptNumber + 1;
163→
164→    // Transition: failed → in-remediation
165→    transitionSession(failedSession.status, "remediation-started");
166→    // Transition: in-remediation → in-progress
167→    transitionSession("in-remediation", "remediation-modules-ready");
168→
169→    // 2e. Update the existing session with new curriculum, status, and attemptNumber
170→    const updatedSession = await sessionRepo.updateSession(
171→      tenantId,
172→      failedSession.id,
173→      {
174→        status: "in-progress",
175→        attemptNumber: newAttemptNumber,
176→        curriculum: remediationCurriculum,
177→        weakAreas: null,
178→        aggregateScore: null,
179→        completedAt: null,
180→      },
181→      failedSession.version,
182→    );
183→
184→    // 2f. Create new module records for the remediation curriculum
185→    const now = new Date().toISOString();
186→    const remediationModuleData = remediationCurriculum.modules.map((m, i) => ({
187→      tenantId,
188→      sessionId: failedSession.id,
189→      moduleIndex: i,
190→      title: m.title,
191→      topicArea: m.topicArea,
192→      jobExpectationIndices: m.jobExpectationIndices,
193→      status: "locked" as const,
194→      content: null,
195→      scenarioResponses: [],
196→      quizAnswers: [],
197→      moduleScore: null,
198→      version: 1,
199→      createdAt: now,
200→      updatedAt: now,
201→    }));
202→
203→    const remediationModules = await sessionRepo.createModules(tenantId, remediationModuleData);
204→
205→    // 2g. Log remediation audit event
206→    await logRemediationInitiated(
207→      storage,
208→      tenantId,
209→      employeeId,
210→      failedSession.id,
211→      newAttemptNumber,
212→      weakAreas.length,
213→      weakAreas,
214→    );
215→
216→    // 2h. Return 201 with updated session + new modules
217→    return NextResponse.json(
218→      { session: updatedSession, modules: remediationModules.map(stripServerFields) },
219→      { status: 201 },
220→    );
221→  }
222→
223→  // 3. No active session and no failed session with attempts remaining — fresh session
224→  // Find confirmed role profile — 404 if none
225→  const profile = await profileRepo.findByEmployee(tenantId, employeeId);
226→  if (!profile) {
227→    return NextResponse.json(
228→      { error: "not_found", message: "No confirmed role profile found" },
229→      { status: 404 },
230→    );
231→  }
232→
233→  // 4. Generate curriculum via AI
234→  let curriculum: Awaited<ReturnType<typeof generateCurriculum>>;
235→  try {
236→    curriculum = await generateCurriculum(profile, { maxModules }, model);
237→  } catch (error) {
238→    if (error instanceof CurriculumGenerationError) {
239→      if (error.code === "ai_unavailable") {
240→        return NextResponse.json(
241→          { error: "ai_unavailable", message: "AI service temporarily unavailable" },
242→          { status: 503 },
243→        );
244→      }
245→      return NextResponse.json(
246→        { error: "generation_failed", message: error.message },
247→        { status: 422 },
248→      );
249→    }
250→    return NextResponse.json(
251→      { error: "internal_error", message: "An unexpected error occurred" },
252→      { status: 500 },
253→    );
254→  }
255→
256→  // 5. Create session record
257→  const now = new Date().toISOString();
258→  const session = await sessionRepo.createSession(tenantId, {
259→    tenantId,
260→    employeeId,
261→    roleProfileId: profile.id,
262→    roleProfileVersion: profile.version,
263→    configHash: snapshot?.configHash ?? "unknown",
264→    appVersion: process.env.APP_VERSION ?? "unknown",
265→    status: "in-progress",
266→    attemptNumber: 1,
267→    curriculum,
268→    aggregateScore: null,
269→    weakAreas: null,
270→    version: 1,
271→    createdAt: now,
272→    updatedAt: now,
273→    completedAt: null,
274→  });
275→
276→  // 6. Create module records for each curriculum module
277→  const moduleData = curriculum.modules.map((m, i) => ({
278→    tenantId,
279→    sessionId: session.id,
280→    moduleIndex: i,
281→    title: m.title,
282→    topicArea: m.topicArea,
283→    jobExpectationIndices: m.jobExpectationIndices,
284→    status: "locked" as const,
285→    content: null,
286→    scenarioResponses: [],
287→    quizAnswers: [],
288→    moduleScore: null,
289→    version: 1,
290→    createdAt: now,
291→    updatedAt: now,
292→  }));
293→
294→  const modules = await sessionRepo.createModules(tenantId, moduleData);
295→
296→  // 7. Log audit event
297→  await logSessionStarted(
298→    storage,
299→    tenantId,
300→    employeeId,
301→    session.id,
302→    1,
303→    profile.version,
304→    snapshot?.configHash ?? "unknown",
305→  );
306→
307→  // 8. Return 201 with session + modules
308→  return NextResponse.json({ session, modules: modules.map(stripServerFields) }, { status: 201 });
309→}
310→
311→// ---------------------------------------------------------------------------
312→// GET — T014: Get current session state
313→// ---------------------------------------------------------------------------
314→
315→export async function GET(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
316→  const { tenant: tenantSlug } = await params;
317→  const tenantId = request.headers.get("x-tenant-id");
318→  const employeeId = request.headers.get("x-employee-id");
319→
320→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
321→    return NextResponse.json(
322→      { error: "unauthorized", message: "Not authenticated" },
323→      { status: 401 },
324→    );
325→  }
326→
327→  await storage.initialize();
328→
329→  // Parse query parameters
330→  const url = new URL(request.url);
331→  const isHistory = url.searchParams.get("history") === "true";
332→
333→  // T030: History mode — return all sessions with their modules
334→  if (isHistory) {
335→    const sessions = await sessionRepo.findSessionHistory(tenantId, employeeId);
336→    const sessionsWithModules = await Promise.all(
337→      sessions.map(async (sess) => {
338→        const modules = await sessionRepo.findModulesBySession(tenantId, sess.id);
339→        const clientModules = modules.map(stripServerFields);
340→        return { session: sess, modules: clientModules };
341→      }),
342→    );
343→    return NextResponse.json(sessionsWithModules);
344→  }
345→
346→  // T014: Default mode — return active or most recent session
347→  let session = await sessionRepo.findActiveSession(tenantId, employeeId);
348→  if (!session) {
349→    const history = await sessionRepo.findSessionHistory(tenantId, employeeId, { limit: 1 });
350→    session = history[0] ?? null;
351→  }
352→
353→  if (!session) {
354→    return NextResponse.json(
355→      { error: "not_found", message: "No training session found" },
356→      { status: 404 },
357→    );
358→  }
359→
360→  // 2. Find modules for this session
361→  const modules = await sessionRepo.findModulesBySession(tenantId, session.id);
362→
363→  // 3. Strip server-only fields (correct answers, rubrics) from module content
364→  const clientModules = modules.map(stripServerFields);
365→
366→  return NextResponse.json({ session, modules: clientModules });
367→}
