 15→/**
 16→ * Abandon training session API route.
 17→ * POST /api/training/{tenant}/abandon — T032
 18→ * Transitions an in-progress or in-remediation session to abandoned.
 19→ */
 20→
 21→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 22→import { logSessionAbandoned } from "@/training/audit";
 23→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 24→import { StateTransitionError, transitionSession } from "@/training/state-machine";
 25→import { NextResponse } from "next/server";
 26→
 27→const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 28→const sessionRepo = new SessionRepository(storage);
 29→
 30→export async function POST(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 31→  const { tenant: tenantSlug } = await params;
 32→  const tenantId = request.headers.get("x-tenant-id");
 33→  const employeeId = request.headers.get("x-employee-id");
 34→
 35→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 36→    return NextResponse.json(
 37→      { error: "unauthorized", message: "Not authenticated" },
 38→      { status: 401 },
 39→    );
 40→  }
 41→
 42→  await storage.initialize();
 43→
 44→  // 1. Find active session — 404 if none
 45→  const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 46→  if (!session) {
 47→    return NextResponse.json(
 48→      { error: "not_found", message: "No active training session found" },
 49→      { status: 404 },
 50→    );
 51→  }
 52→
 53→  // 2. Guard: session must be in-progress or in-remediation
 54→  if (session.status !== "in-progress" && session.status !== "in-remediation") {
 55→    return NextResponse.json(
 56→      {
 57→        error: "conflict",
 58→        message: `Session is in '${session.status}' state, expected 'in-progress' or 'in-remediation'`,
 59→      },
 60→      { status: 409 },
 61→    );
 62→  }
 63→
 64→  // 3. Validate state transition
 65→  let nextStatus: ReturnType<typeof transitionSession>;
 66→  try {
 67→    nextStatus = transitionSession(session.status, "session-abandoned");
 68→  } catch (err) {
 69→    if (err instanceof StateTransitionError) {
 70→      return NextResponse.json({ error: "conflict", message: err.message }, { status: 409 });
 71→    }
 72→    throw err;
 73→  }
 74→
 75→  // 4. Update session to abandoned with completedAt
 76→  const now = new Date().toISOString();
 77→  let updatedSession: Awaited<ReturnType<typeof sessionRepo.updateSession>>;
 78→  try {
 79→    updatedSession = await sessionRepo.updateSession(
 80→      tenantId,
 81→      session.id,
 82→      {
 83→        status: nextStatus,
 84→        completedAt: now,
 85→      },
 86→      session.version,
 87→    );
 88→  } catch (err) {
 89→    if (err instanceof VersionConflictError) {
 90→      return NextResponse.json(
 91→        { error: "conflict", message: "Session was modified by another request" },
 92→        { status: 409 },
 93→      );
 94→    }
 95→    throw err;
 96→  }
 97→
 98→  // 5. Count modules completed (status "scored")
 99→  const modules = await sessionRepo.findModulesBySession(tenantId, session.id);
100→  const modulesCompleted = modules.filter((m) => m.status === "scored").length;
101→  const totalModules = modules.length;
102→
103→  // 6. Log audit event
104→  await logSessionAbandoned(
105→    storage,
106→    tenantId,
107→    employeeId,
108→    session.id,
109→    session.attemptNumber,
110→    modulesCompleted,
111→    totalModules,
112→  );
113→
114→  // 7. Return 200 with updated session
115→  return NextResponse.json({ session: updatedSession }, { status: 200 });
116→}
