                    ))}
                  </fieldset>
                ) : (
                  <div>
                    <label
                      htmlFor={`quiz-free-text-${q.id}`}
                      style={{
                        display: "block",
                        fontWeight: 500,
                        marginBottom: "0.5rem",
                        fontSize: "0.875rem",
                      }}
