  it("throws EvaluationError with code 'ai_unavailable' when generateObject throws", async () => {
    vi.mocked(generateObject).mockRejectedValue(new Error("503 Service Unavailable"));

    await expect(
      evaluateFreeText(
        "What is phishing?",
        "Award full marks for ...",
        "Phishing is ...",
        makeMockModel(),
      ),
    ).rejects.toThrow(EvaluationError);

    await expect(
      evaluateFreeText(
        "What is phishing?",
        "Award full marks for ...",
        "Phishing is ...",
        makeMockModel(),
      ),
    ).rejects.toMatchObject({ code: "ai_unavailable" });
  });

  // Test 9: Throws EvaluationError with code "evaluation_failed" when response exceeds 2000 chars
  it("throws EvaluationError with code 'evaluation_failed' when response exceeds 2000 chars", async () => {
    const longResponse = "x".repeat(2001);

    await expect(
      evaluateFreeText(
        "What is phishing?",
        "Award full marks for ...",
        longResponse,
        makeMockModel(),
      ),
    ).rejects.toThrow(EvaluationError);

    await expect(
      evaluateFreeText(
        "What is phishing?",
        "Award full marks for ...",
        longResponse,
        makeMockModel(),
      ),
    ).rejects.toMatchObject({ code: "evaluation_failed" });
  });

  it("does not throw when response is exactly 2000 chars", async () => {
    const exactResponse = "x".repeat(2000);
    // biome-ignore lint/suspicious/noExplicitAny: mock return type cannot be fully typed
    vi.mocked(generateObject).mockResolvedValue(makeValidMockResult() as any);

    await expect(
      evaluateFreeText(
        "What is phishing?",
        "Award full marks for ...",
        exactResponse,
        makeMockModel(),
      ),
    ).resolves.toBeDefined();
  });

  // Test 10: EvaluationError has correct name, message, code properties
  it("EvaluationError has correct name, message, and code properties", async () => {
    vi.mocked(generateObject).mockRejectedValue(new Error("Connection refused"));

    let caughtError: unknown;
    try {
      await evaluateFreeText(
        "What is phishing?",
        "Award full marks for ...",
        "Phishing is ...",
        makeMockModel(),
      );
    } catch (err) {
      caughtError = err;
    }

    expect(caughtError).toBeInstanceOf(EvaluationError);
    const error = caughtError as EvaluationError;
    expect(error.name).toBe("EvaluationError");
    expect(typeof error.message).toBe("string");
    expect(error.message.length).toBeGreaterThan(0);
    expect(error.code).toBe("ai_unavailable");
  });

  it("EvaluationError for exceeded response length has correct properties", async () => {
    const longResponse = "x".repeat(2001);

    let caughtError: unknown;
    try {
      await evaluateFreeText(
        "What is phishing?",
        "Award full marks for ...",
        longResponse,
        makeMockModel(),
      );
    } catch (err) {
      caughtError = err;
    }

    expect(caughtError).toBeInstanceOf(EvaluationError);
    const error = caughtError as EvaluationError;
    expect(error.name).toBe("EvaluationError");
    expect(error.code).toBe("evaluation_failed");
  });

  // Test 11: Temperature is set to 0
  it("sets temperature to 0", async () => {
    // biome-ignore lint/suspicious/noExplicitAny: mock return type cannot be fully typed
    vi.mocked(generateObject).mockResolvedValue(makeValidMockResult() as any);

    await evaluateFreeText(
      "What is phishing?",
      "Award full marks for ...",
      "Phishing is ...",
      makeMockModel(),
    );

    const callArgs = vi.mocked(generateObject).mock.calls[0][0];
    expect(callArgs.temperature).toBe(0);
  });

  // Test 12: FreeTextEvaluationSchema is used (check schema passed to generateObject)
  it("passes FreeTextEvaluationSchema to generateObject", async () => {
    // biome-ignore lint/suspicious/noExplicitAny: mock return type cannot be fully typed
    vi.mocked(generateObject).mockResolvedValue(makeValidMockResult() as any);

    await evaluateFreeText(
      "What is phishing?",
      "Award full marks for ...",
      "Phishing is ...",
      makeMockModel(),
    );

    const callArgs = vi.mocked(generateObject).mock.calls[0][0];
    expect(callArgs.schema).toBe(FreeTextEvaluationSchema);
  });
});

